class Solution:
    def numDecodings(self, s: str) -> int:
        n = len(s)
        if n == 0:
            return 1

        dp_prev2 = 1 

        if s[0] == '0':
            dp_prev1 = 0
        else:
            dp_prev1 = 1

        for i in range(1, n):
            dp_curr = 0

            if s[i] != '0':
                dp_curr += dp_prev1

            two_digits = int(s[i-1:i+1])

            if 10 <= two_digits <= 26:
                dp_curr += dp_prev2

            dp_prev2 = dp_prev1
            dp_prev1 = dp_curr

        return dp_prev1
